import React, { useState } from "react";

/* =====================================================
   Decisions.jsx
   - Professional Replacement Approval Page
   - UI bugs FIXED
   - Dummy data INCLUDED
   - Drawer behavior STABLE
   ===================================================== */

// -------------------- DUMMY DATA --------------------
const DUMMY_REQUESTS = [
  {
    id: "REQ-001",
    systemId: "SYS-8472",
    owner: "Manufacturing / Line B",
    aiVerdict: "approve",
    confidence: 94,
    estimatedCost: 4200,
    riskIfDelayed: "High",
    status: "pending",
    financial: {
      replaceEstimate: 4200,
      repairEstimate: 1800,
    },
  },
  {
    id: "REQ-002",
    systemId: "SYS-9031",
    owner: "Finance / Analytics",
    aiVerdict: "reject",
    confidence: 78,
    estimatedCost: 1600,
    riskIfDelayed: "Medium",
    status: "pending",
    financial: {
      replaceEstimate: 3500,
      repairEstimate: 900,
    },
  },
  {
    id: "REQ-003",
    systemId: "SYS-7720",
    owner: "R&D / Lab",
    aiVerdict: "approve",
    confidence: 85,
    estimatedCost: 1200,
    riskIfDelayed: "Low",
    status: "approved",
    financial: {
      replaceEstimate: 1200,
      repairEstimate: 200,
    },
  },
];

// -------------------- HELPERS --------------------
const riskBadge = (r) =>
  r === "High"
    ? "bg-red-50 text-red-700"
    : r === "Medium"
    ? "bg-yellow-50 text-yellow-700"
    : "bg-green-50 text-green-700";

const statusBadge = (s) =>
  s === "approved"
    ? "bg-green-50 text-green-700"
    : s === "rejected"
    ? "bg-red-50 text-red-700"
    : "bg-yellow-50 text-yellow-700";

// -------------------- COMPONENT --------------------
export default function Decisions() {
  const [requests, setRequests] = useState(DUMMY_REQUESTS);
  const [selected, setSelected] = useState(null);
  const [drawerOpen, setDrawerOpen] = useState(false);
  const [actionReason, setActionReason] = useState("");

  // ---- SAFE OPEN / CLOSE ----
  const openDrawer = (req) => {
    setSelected(req);
    setActionReason("");
    setDrawerOpen(true);
  };

  const closeDrawer = () => {
    setDrawerOpen(false);
    setSelected(null);
    setActionReason("");
  };

  const approveReplacement = () => {
    if (actionReason.length < 5) {
      alert("Please enter a reason (min 5 characters)");
      return;
    }

    setRequests((prev) =>
      prev.map((r) =>
        r.id === selected.id ? { ...r, status: "approved" } : r
      )
    );

    closeDrawer();
  };

  const rejectRequest = () => {
    if (actionReason.length < 5) {
      alert("Please enter a reason (min 5 characters)");
      return;
    }

    setRequests((prev) =>
      prev.map((r) =>
        r.id === selected.id ? { ...r, status: "rejected" } : r
      )
    );

    closeDrawer();
  };

  return (
    <div className="p-6 bg-gray-50 min-h-[calc(100vh-4rem)]">

      {/* ================= HEADER ================= */}
      <div className="mb-6">
        <h1 className="text-2xl font-semibold text-slate-900">
          Replacement Decisions
        </h1>
        <p className="text-sm text-slate-600">
          AI-validated hardware replacement approvals
        </p>
      </div>

      {/* ================= TABLE ================= */}
      <div className="bg-white border rounded-lg shadow overflow-x-auto">
        <table className="min-w-full divide-y">
          <thead className="bg-gray-50 text-xs uppercase text-gray-600">
            <tr>
              <th className="px-4 py-3 text-left">Request ID</th>
              <th className="px-4 py-3 text-left">System</th>
              <th className="px-4 py-3 text-left">Owner</th>
              <th className="px-4 py-3 text-right">Confidence</th>
              <th className="px-4 py-3 text-left">Risk</th>
              <th className="px-4 py-3 text-left">Status</th>
              <th className="px-4 py-3 text-left">Action</th>
            </tr>
          </thead>

          <tbody className="divide-y">
            {requests.map((r) => (
              <tr key={r.id} className="hover:bg-gray-50">
                <td className="px-4 py-3 text-sky-600 font-medium">
                  <button onClick={() => openDrawer(r)} className="hover:underline">
                    {r.id}
                  </button>
                </td>
                <td className="px-4 py-3">{r.systemId}</td>
                <td className="px-4 py-3">{r.owner}</td>
                <td className="px-4 py-3 text-right">{r.confidence}%</td>
                <td className="px-4 py-3">
                  <span className={`px-2 py-1 rounded-full text-xs ${riskBadge(r.riskIfDelayed)}`}>
                    {r.riskIfDelayed}
                  </span>
                </td>
                <td className="px-4 py-3">
                  <span className={`px-2 py-1 rounded-full text-xs ${statusBadge(r.status)}`}>
                    {r.status}
                  </span>
                </td>
                <td className="px-4 py-3">
                  <button
                    onClick={() => openDrawer(r)}
                    className="px-3 py-1.5 border rounded-md text-sm hover:bg-slate-50"
                  >
                    View Decision
                  </button>
                </td>
              </tr>
            ))}
          </tbody>
        </table>
      </div>

      {/* ================= DRAWER ================= */}
      {drawerOpen && selected && (
        <div className="fixed inset-0 z-50">

          {/* Overlay */}
          <div
            className="absolute inset-0 bg-black/40"
            onClick={closeDrawer}
          />

          {/* Drawer */}
          <aside
            className="absolute right-0 top-0 h-full w-full sm:w-[720px] bg-white shadow-xl z-[60] overflow-y-auto"
            onClick={(e) => e.stopPropagation()}
          >
            <div className="p-5 border-b flex justify-between">
              <h2 className="text-lg font-semibold">
                Review Decision — {selected.systemId}
              </h2>
              <button
                onClick={closeDrawer}
                className="px-3 py-1 bg-slate-100 rounded-md text-sm"
              >
                Close
              </button>
            </div>

            <div className="p-5 space-y-6">
              <div className="bg-gray-50 p-4 rounded-md">
                <div className="text-sm">
                  <strong>AI Recommendation:</strong>{" "}
                  {selected.aiVerdict.toUpperCase()}
                </div>
                <div className="text-sm mt-1">
                  <strong>Confidence:</strong> {selected.confidence}%
                </div>
              </div>

              <div className="bg-white border p-4 rounded-md">
                <div className="text-sm font-semibold mb-2">
                  Financial Impact
                </div>
                <div className="text-sm">
                  Replacement: ${selected.financial.replaceEstimate}
                </div>
                <div className="text-sm">
                  Repair: ${selected.financial.repairEstimate}
                </div>
              </div>

              <div className="bg-white border p-4 rounded-md">
                <div className="text-sm font-semibold mb-2">
                  Reviewer Notes
                </div>
                <textarea
                  className="w-full border rounded-md p-2 min-h-[90px]"
                  placeholder="Enter decision rationale (required)"
                  value={actionReason}
                  onChange={(e) => setActionReason(e.target.value)}
                />

                <div className="flex gap-3 mt-4">
                  <button
                    onClick={approveReplacement}
                    className="bg-green-600 text-white px-4 py-2 rounded-md text-sm"
                  >
                    Approve Replacement
                  </button>
                  <button
                    onClick={rejectRequest}
                    className="bg-red-50 text-red-700 border px-4 py-2 rounded-md text-sm"
                  >
                    Reject Claim
                  </button>
                </div>
              </div>
            </div>
          </aside>
        </div>
      )}
    </div>
  );
}
